```java
import java.net.MalformedURLException;
import java.net.URL;

public class RedirectHandler {
    /**
     * 处理重定向逻辑
     * @param location 重定向目标URL（非null、非空且格式有效）
     * @return 重定向响应（包含状态码和Location头）
     * @throws IllegalArgumentException 当location为null、空字符串或格式无效时抛出
     */
    public RedirectResponse redirect(String location) {
        if (location == null) {
            throw new IllegalArgumentException("Location must not be null");
        }
        if (location.trim().isEmpty()) {
            throw new IllegalArgumentException("Location must not be empty");
        }
        try {
            new URL(location); // 验证URL格式
        } catch (MalformedURLException e) {
            throw new IllegalArgumentException("Location is not a valid URL", e);
        }
        return new RedirectResponse(302, location); // 302临时重定向
    }

    // 内部响应类（模拟HTTP重定向响应）
    public static class RedirectResponse {
        private final int statusCode;
        private final String location;

        public RedirectResponse(int statusCode, String location) {
            this.statusCode = statusCode;
            this.location = location;
        }

        public int getStatusCode() { return statusCode; }
        public String getLocation() { return location; }
    }
}
```


