```java
import java.util.EnumMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

public class RouteManager {
    private final Map<HttpMethod, Set<String>> routes = new EnumMap<>(HttpMethod.class);

    public boolean addRoute(HttpMethod httpMethod, String route) {
        // 参数校验
        if (httpMethod == null) {
            throw new IllegalArgumentException("HTTP method cannot be null");
        }
        if (route == null || route.trim().isEmpty()) {
            throw new IllegalArgumentException("Route cannot be null or empty");
        }
        // 初始化HTTP方法对应的路由集合
        routes.putIfAbsent(httpMethod, new HashSet<>());
        Set<String> methodRoutes = routes.get(httpMethod);
        // 检查路由是否已存在
        if (methodRoutes.contains(route)) {
            return false; // 已存在，添加失败
        }
        methodRoutes.add(route);
        return true; // 添加成功
    }

    // 辅助方法：用于测试验证路由是否存在
    public boolean hasRoute(HttpMethod httpMethod, String route) {
        return routes.containsKey(httpMethod) && routes.get(httpMethod).contains(route);
    }

    public enum HttpMethod { GET, POST, PUT, DELETE }
}
```


